      box(1.5, 0.5, 1.7, body, 0, 1.06, -0.05);                // cabin/greenhouse
      box(1.46, 0.42, 0.06, 0x1a2230, 0, 1.06, 0.82, 0x0a0e14); // windshield hint (dark glass)
