      const cabCol = 0xd23a2f, cargo = 0xe6e2da;               // red cab, off-white box
      box(2.0, 0.42, 5.9, 0x2a2d33, 0, 0.5, 0);                // chassis
      box(1.98, 1.4, 1.5, cabCol, 0, 1.42, 2.15);              // cab
      box(1.72, 0.8, 0.06, 0x18202c, 0, 1.6, 2.92, 0x0a0e14);  // windshield
      box(2.04, 2.2, 3.5, cargo, 0, 1.9, -0.85);               // tall cargo box
      box(2.06, 0.16, 3.54, 0xcbc6bc, 0, 3.02, -0.85);         // cargo roof lip
