      box(2.1, 1.7, 7.8, yellow, 0, 1.5, 0);                   // long body
      box(2.12, 0.55, 7.7, 0x14171e, 0, 1.98, 0, 0x05070b);    // window strip (dark)
      box(2.14, 0.22, 7.6, 0x1a1c22, 0, 1.34, 0, 0x08090c);    // black side stripe
