    const baseSpeed = Math.max(1, Math.min(40, +traffic.speed || 8));
    // spawn: even arc spacing across the loop MINUS a ~30u exclusion zone around s=0 (start grid
    // must be clear at GO), round-robin across the 4 lanes, small deterministic jitter.
    let s = 0x7A0FF1c;
    const rnd = ()=>{ s = (s*1103515245 + 12345) & 0x7fffffff; return s/0x7fffffff; };
